solutions.javascript:
// Define a function to calculate the custom property value for the parent element
function calculateCustomProperty(parentElement) {
  // If the parent element has at least one child, return the maximum value of its children's custom property values
  if (parentElement.children.length > 0) {
    return Math.max(...parentElement.children.map((child) => parseFloat(child.style.getPropertyValue('--value'))))
  }
  // If the parent element has no children, return 0
  return 0;
}
